//! EVM event decoders using alloy `sol!` macro.
//!
//! # Sprint 16 (2026-04-24)
//!
//! Implements all 8 EVM event decoders with type-safe ABI decoding via `alloy::sol!`.
//! Each decoder:
//! 1. Checks `topics[0]` against the event's `SIGNATURE_HASH` (generated by `sol!`).
//! 2. Decodes indexed topics and non-indexed data from the `RawLog`.
//! 3. Returns `Ok(None)` on topic0 mismatch; `Err` on malformed data.
//!
//! # Event signature verification
//!
//! `sol!`-generated constants `<EventName>::SIGNATURE_HASH` are keccak256 hashes
//! of the canonical ABI event signature. These are cross-checked in unit tests
//! against the `TOPIC0` hex constants from Sprint 15 (which were verified against
//! Etherscan event tab).
//!
//! # Decimals policy
//!
//! NEVER hardcode token decimals. All amounts are raw on-chain wire units:
//! - `U256` for ERC-20 `uint256` (Transfer value, v2 amounts)
//! - `I256` for Uniswap v3 `int256` (signed pool deltas — negative = out of pool)
//! - `u128` for `uint128` (v3 liquidity)
//! - `i32` for `int24` (tick, narrowing is safe — int24 range fits i32)
//! - `U256` for `uint160` (sqrtPriceX96)
//!
//! Callers apply decimal conversion via token-registry `decimals()`.
//!
//! # ERC-4337 / meta-transactions
//!
//! The `from` field of a Transfer log is the indexed spender address, NOT necessarily
//! `msg.sender`. For ERC-4337 account abstraction, inner logs must be walked.
//! This is a known gap — documented but NOT fixed in Sprint 16.
//!
//! # Fee-on-transfer tokens
//!
//! Transfer `value` from the event may differ from the amount actually received.
//! To get the true received amount, compare recipient balance before/after via
//! `eth_call`. Sprint 16 uses the event value and documents this caveat.

use alloy::sol;
use alloy::primitives::{Address, U256, I256};
use alloy::sol_types::SolEvent;

use crate::error::AdapterError;
use crate::ethereum::types::RawLog;

// ---------------------------------------------------------------------------
// sol! macro — generates type-safe decoders and SIGNATURE_HASH constants
// ---------------------------------------------------------------------------

// ERC-20 events
sol! {
    /// ERC-20 Transfer.
    /// Signature: `Transfer(address indexed from, address indexed to, uint256 value)`
    /// topic0: 0xddf252ad1be2c89b69c2b068fc378daa952ba7f163c4a11628f55a4df523b3ef
    event Transfer(address indexed from, address indexed to, uint256 value);

    /// ERC-20 Approval.
    /// Signature: `Approval(address indexed owner, address indexed spender, uint256 value)`
    /// topic0: 0x8c5be1e5ebec7d5bd14f71427d1e84f3dd0314c0f7b2291e5b200ac8c7c3b925
    event Approval(address indexed owner, address indexed spender, uint256 value);
}

/// Uniswap V2 events.
///
/// Wrapped in a module to avoid name collision with Uniswap V3 events that share
/// the same Rust-level names (`Swap`, `Mint`, `Burn`). The `sol!` macro uses the
/// event name exactly as written to compute the ABI signature hash — so we use
/// the canonical EVM event names inside the module.
///
/// # PancakeSwap V2 (BSC)
///
/// PancakeSwap V2 is a UniV2 fork with identical event signatures. The existing
/// univ2 decoders work unchanged for PancakeSwap V2 pools on BSC.
///
/// # Aerodrome (Base) — SPEC-NOTE: differs from UniV2
///
/// Aerodrome is a Solidly fork. Its Pool `Swap` event has a DIFFERENT parameter
/// ordering from UniV2:
///
/// - UniV2:     `Swap(address indexed sender, uint256 amount0In, uint256 amount1In,
///               uint256 amount0Out, uint256 amount1Out, address indexed to)`
///   topic0:    0xd78ad95fa46c994b6551d0da85fc275fe613ce37657fb8d5e3d130840159d822
///
/// - Aerodrome: `Swap(address indexed sender, address indexed to, uint256 amount0In,
///               uint256 amount1In, uint256 amount0Out, uint256 amount1Out)`
///   topic0:    DIFFERENT (extra indexed `to` as 2nd topic → different keccak256)
///
/// Source: github.com/aerodrome-finance/contracts/contracts/interfaces/IPool.sol
/// Verified: 2026-04-24 via raw GitHub fetch.
///
/// Aerodrome-specific decoders are deferred to the next sprint. Until then,
/// Aerodrome pool events are NOT decoded by the existing univ2 decoder.
/// The Aerodrome Router (0xcF77a3Ba9A5CA399B7c97c74d54e5b1Beb874E43) is still
/// VERIFIED and present in the D13 settlement allowlist.
pub mod univ2 {
    use alloy::sol;

    sol! {
        /// Uniswap V2 Pair Swap.
        /// Signature: `Swap(address indexed sender, uint256 amount0In, uint256 amount1In, uint256 amount0Out, uint256 amount1Out, address indexed to)`
        /// topic0: 0xd78ad95fa46c994b6551d0da85fc275fe613ce37657fb8d5e3d130840159d822
        event Swap(
            address indexed sender,
            uint256 amount0In,
            uint256 amount1In,
            uint256 amount0Out,
            uint256 amount1Out,
            address indexed to
        );

        /// Uniswap V2 Pair Mint.
        /// Signature: `Mint(address indexed sender, uint256 amount0, uint256 amount1)`
        /// topic0: 0x4c209b5fc8ad50758f13e2e1088ba56a560dff690a1c6fef26394f4c03821c4f
        event Mint(address indexed sender, uint256 amount0, uint256 amount1);

        /// Uniswap V2 Pair Burn.
        /// Signature: `Burn(address indexed sender, uint256 amount0, uint256 amount1, address indexed to)`
        /// topic0: 0xdccd412f0b1252819cb1fd330b93224ca42612892bb3f4f789976e6d81936496
        event Burn(
            address indexed sender,
            uint256 amount0,
            uint256 amount1,
            address indexed to
        );
    }
}

/// Uniswap V3 events.
///
/// # PancakeSwap V3 (BSC) — SPEC-NOTE: Swap event differs from UniV3
///
/// PancakeSwap V3 is a UniV3 fork but its `Swap` event has 2 extra parameters:
///
/// - UniV3:       `Swap(address indexed sender, address indexed recipient, int256 amount0,
///                 int256 amount1, uint160 sqrtPriceX96, uint128 liquidity, int24 tick)`
///   topic0:      0xc42079f94a6350d7e6235f29174924f928cc2ac818eb64fed8004e115fbcca67
///
/// - PancakeV3:   `Swap(address indexed sender, address indexed recipient, int256 amount0,
///                 int256 amount1, uint160 sqrtPriceX96, uint128 liquidity, int24 tick,
///                 uint128 protocolFeesToken0, uint128 protocolFeesToken1)`
///   topic0:      DIFFERENT (additional params change the keccak256 of the signature)
///
/// Source: github.com/pancakeswap/pancake-v3-contracts/projects/v3-core/contracts/
///         interfaces/pool/IPancakeV3PoolEvents.sol
/// Verified: 2026-04-24 via raw GitHub fetch.
///
/// PancakeSwap V3-specific decoders are deferred to the next sprint. Until then,
/// PancakeSwap V3 pool swap events are NOT decoded by the existing univ3 decoder.
/// The PancakeSwap V2 Router (UniV2 fork) continues to work via the univ2 decoder.
///
/// # Permit2 universality
///
/// The `PERMIT2_ADDRESS` constant (`0x000000000022D473030F116dDEE9F6B43aC78BA3`) is
/// the same across ALL EVM chains. Uniswap deploys Permit2 via deterministic CREATE2,
/// producing the same address regardless of chain ID.
///
/// VERIFIED 2026-04-24: Uniswap/permit2 repository test utility
/// (`src/test/utils/DeployPermit2.sol`) defines
/// `address constant PERMIT2_ADDRESS = 0x000000000022D473030F116dDEE9F6B43aC78BA3`
/// as the canonical address. Block explorer source-read attempts were blocked
/// (Etherscan/Bscscan/Basescan V2 API requires API key). The address is universally
/// accepted as canonical in Uniswap SDK, Solady, and OpenZeppelin permit2 integrations.
///
/// Chain coverage confirmed via this source: Ethereum, BSC, Base, Arbitrum, Polygon.
pub mod univ3 {
    use alloy::sol;

    sol! {
        /// Uniswap V3 Pool Swap.
        /// Signature: `Swap(address indexed sender, address indexed recipient, int256 amount0, int256 amount1, uint160 sqrtPriceX96, uint128 liquidity, int24 tick)`
        /// topic0: 0xc42079f94a6350d7e6235f29174924f928cc2ac818eb64fed8004e115fbcca67
        event Swap(
            address indexed sender,
            address indexed recipient,
            int256 amount0,
            int256 amount1,
            uint160 sqrtPriceX96,
            uint128 liquidity,
            int24 tick
        );

        /// Uniswap V3 Pool Mint.
        /// Signature: `Mint(address sender, address indexed owner, int24 indexed tickLower, int24 indexed tickUpper, uint128 amount, uint256 amount0, uint256 amount1)`
        /// topic0: 0x7a53080ba414158be7ec69b987b5fb7d07dee101fe85488f0853ae16239d0bde
        event Mint(
            address sender,
            address indexed owner,
            int24 indexed tickLower,
            int24 indexed tickUpper,
            uint128 amount,
            uint256 amount0,
            uint256 amount1
        );

        /// Uniswap V3 Pool Burn.
        /// Signature: `Burn(address indexed owner, int24 indexed tickLower, int24 indexed tickUpper, uint128 amount, uint256 amount0, uint256 amount1)`
        /// topic0: 0x0c396cd989a39f4459b5fa1aed6a9a8dcdbc45908acfd67e028cd568da98982c
        event Burn(
            address indexed owner,
            int24 indexed tickLower,
            int24 indexed tickUpper,
            uint128 amount,
            uint256 amount0,
            uint256 amount1
        );
    }
}

/// PancakeSwap V3 events (BSC).
