///     address indexed sender,
///     address indexed recipient,
///     int256 amount0,
///     int256 amount1,
///     uint160 sqrtPriceX96,
///     uint128 liquidity,
///     int24 tick,
///     uint128 protocolFeesToken0,
///     uint128 protocolFeesToken1
/// );
/// ```
///
/// # Mint and Burn (SPEC-NOTE)
///
/// PancakeSwap V3 Mint and Burn events were not fetched this sprint. Based on the
/// UniV3 fork architecture, they are expected to match the UniV3 signatures exactly.
/// Until verified, D13 (sandwich detection) only needs Swap events; Mint/Burn for
/// PancakeSwap V3 are deferred. If they match UniV3, the existing univ3::Mint and
/// univ3::Burn decoders suffice. Verify via BSCscan event tab next sprint.
pub mod pancake_v3 {
    use alloy::sol;

    sol! {
        /// PancakeSwap V3 Pool Swap.
        ///
        /// Signature: `Swap(address indexed sender, address indexed recipient,
        ///   int256 amount0, int256 amount1, uint160 sqrtPriceX96, uint128 liquidity,
        ///   int24 tick, uint128 protocolFeesToken0, uint128 protocolFeesToken1)`
        ///
        /// topic0: derived from sol! SIGNATURE_HASH (different from UniV3 due to extra params)
        ///
        /// Source: IPancakeV3PoolEvents.sol, fetched 2026-04-24 via WebFetch.
        event Swap(
            address indexed sender,
            address indexed recipient,
            int256 amount0,
            int256 amount1,
            uint160 sqrtPriceX96,
            uint128 liquidity,
            int24 tick,
            uint128 protocolFeesToken0,
            uint128 protocolFeesToken1
        );
    }
}

