/// Aerodrome factory events (Base chain) — Solidly fork pool factory.
///
/// # Verification
///
/// Source: `github.com/aerodrome-finance/contracts/contracts/interfaces/factories/IPoolFactory.sol`
/// Fetched: 2026-04-24 via WebFetch (raw.githubusercontent.com).
/// Confirmed event signature:
/// ```solidity
/// event PoolCreated(
///     address indexed token0,
///     address indexed token1,
///     bool indexed stable,
///     address pool,
///     uint256
/// );
/// ```
///
/// # Key difference from UniV2/UniV3 factory events
///
/// The Aerodrome factory emits `bool indexed stable` as the third indexed parameter
/// instead of `uint24 indexed fee` (UniV3). The `uint256` at the end is an anonymous
/// pool count (same role as UniV2's `unused` pair index — not used by detectors).
///
/// Factory address on Base: `0x420dd381b31aef6683db6b902084cb0ffece40da`
/// (verified via Aerodrome documentation + Basescan, 2026-04-24).
pub mod aerodrome_factory {
    use alloy::sol;

    sol! {
        /// Aerodrome Factory PoolCreated event (Base chain, Solidly fork).
        ///
        /// Signature: `PoolCreated(address indexed token0, address indexed token1,
        ///   bool indexed stable, address pool, uint256)`
        ///
        /// topic0: derived from sol! SIGNATURE_HASH (distinct from UniV2/UniV3 factory events).
        ///
        /// Source: IPoolFactory.sol (aerodrome-finance/contracts), fetched 2026-04-24 via WebFetch.
        ///
        /// `stable` is `true` for Solidly stable pools (stableswap invariant x^3*y + x*y^3 = k)
        /// and `false` for volatile pools (constant-product invariant x*y = k).
        event PoolCreated(
            address indexed token0,
            address indexed token1,
            bool indexed stable,
            address pool,
            uint256
        );
    }
}

