/// Uniswap V2 factory events — emitted by the UniV2 factory contract to signal new pair creation.
///
/// # Factory addresses (canonical, verified against each chain's block explorer)
///
/// - Ethereum:  `0x5C69bEe701ef814a2B6a3EDD4B1652CB9cc5aA6f`
///   Source: Uniswap V2 deployment docs. Verified 2026-04-25.
/// - BSC:       `0xcA143Ce32Fe78f1f7019d7d551a6402fC5350c73` (PancakeSwap V2 factory)
///   Source: pancakeswap.finance/info. PancakeSwap V2 is a UniV2 fork — identical ABI.
/// - Base:      `0x8909Dc15e40173Ff4699343b6eB8132c65e18eC6` (Uniswap V2 on Base)
///   SPEC-NOTE: Verify against Basescan; address sourced from Uniswap deployments-v2 repo.
/// - Arbitrum:  `0xf1D7CC64Fb4452F05c498126312eBE29f30Fbcf9`
///   SPEC-NOTE: Verify against Arbiscan; address sourced from Uniswap deployments-v2 repo.
/// - Polygon:   `0x9e5A52f57b3038F1B8EeE45F28b3C1967e22799C`
///   SPEC-NOTE: Verify against Polygonscan; address sourced from Uniswap deployments-v2 repo.
///
/// # PairCreated event ABI
///
/// ```solidity
/// event PairCreated(
///     address indexed token0,
///     address indexed token1,
///     address pair,
///     uint256 unused   // sequential pair index, not used by detectors
/// );
/// ```
///
/// topic0: `0x0d3648bd0f6ba80134a33ba9275ac585d9d315f0ad8355cddefde31afa28d0e9`
/// Source: keccak256("PairCreated(address,address,address,uint256)"), verified via sol! SIGNATURE_HASH.
///
/// # UniV3 factory — see `uniswap_v3_factory` module
pub mod uniswap_v2_factory {
    use alloy::sol;

    sol! {
        /// Uniswap V2 Factory PairCreated event.
        ///
        /// Emitted by the UniV2 factory when a new trading pair is deployed.
        /// `pair` is the new pair contract address. `unused` is the sequential pair index
        /// (1-indexed count of all pairs created by this factory) — not used by detectors.
        ///
        /// Signature: `PairCreated(address indexed token0, address indexed token1, address pair, uint256 unused)`
        /// topic0: 0x0d3648bd0f6ba80134a33ba9275ac585d9d315f0ad8355cddefde31afa28d0e9
        event PairCreated(
            address indexed token0,
            address indexed token1,
            address pair,
            uint256 unused
        );
    }
}

