/// Aerodrome events (Base chain) — Solidly fork.
///
/// # Verification (Sprint 44)
///
/// Source: `github.com/aerodrome-finance/contracts/contracts/interfaces/IPool.sol`
/// Fetched: 2026-04-24 (Swap) and 2026-04-24 (Mint/Burn, Sprint 44) via WebFetch.
///
/// ## Mint
///
/// Aerodrome Mint: `Mint(address indexed sender, uint256 amount0, uint256 amount1)`
/// Same ABI as UniV2 Mint — topic0 is IDENTICAL to `UNISWAP_V2_MINT_TOPIC0`.
///   `keccak256("Mint(address,uint256,uint256)") = 0x4c209b5fc8ad50758f13e2e1088ba56a560dff690a1c6fef26394f4c03821c4f`
/// The existing `univ2::Mint` decoder can be reused for Aerodrome pools.
///
/// ## Burn
///
/// Aerodrome Burn: `Burn(address indexed sender, address indexed to, uint256 amount0, uint256 amount1)`
/// **DIFFERENT** from UniV2 Burn (`Burn(address,uint256,uint256,address)` — different param order).
///   `keccak256("Burn(address,address,uint256,uint256)") = 0x5d624aa9c148153ab3446c1b154f660ee7701e549fe9b62dab7171b1c80e6fa8`
/// Aerodrome Burn has `to` as the second parameter (indexed), not the last.
///
/// ## Swap (already shipped Sprint 40)
///
/// Aerodrome Swap: `Swap(address indexed sender, address indexed to, ...)`
/// Different topic0 from UniV2 due to extra indexed `to` as 2nd parameter.
pub mod aerodrome {
    use alloy::sol;

    sol! {
        /// Aerodrome Pool Swap.
        ///
        /// Signature: `Swap(address indexed sender, address indexed to,
        ///   uint256 amount0In, uint256 amount1In, uint256 amount0Out, uint256 amount1Out)`
        ///
        /// topic0: derived from sol! SIGNATURE_HASH (different from UniV2 — extra indexed `to`)
        ///
        /// Source: IPool.sol (aerodrome-finance/contracts), fetched 2026-04-24 via WebFetch.
        event Swap(
            address indexed sender,
            address indexed to,
            uint256 amount0In,
            uint256 amount1In,
            uint256 amount0Out,
            uint256 amount1Out
        );

        /// Aerodrome Pool Mint (liquidity provision).
        ///
        /// Signature: `Mint(address indexed sender, uint256 amount0, uint256 amount1)`
        ///
        /// This is IDENTICAL to UniV2 Mint — same ABI, same topic0.
        /// topic0: 0x4c209b5fc8ad50758f13e2e1088ba56a560dff690a1c6fef26394f4c03821c4f
        ///
        /// Source: IPool.sol (aerodrome-finance/contracts), fetched 2026-04-24 via WebFetch.
        /// Verified: SIGNATURE_HASH matches UNISWAP_V2_MINT_TOPIC0 in tests.
        event Mint(address indexed sender, uint256 amount0, uint256 amount1);

        /// Aerodrome Pool Burn (liquidity removal).
        ///
        /// Signature: `Burn(address indexed sender, address indexed to, uint256 amount0, uint256 amount1)`
        ///
        /// **DIFFERENT** from UniV2 Burn: `to` is the second parameter (indexed), not the last.
        /// UniV2: `Burn(address indexed sender, uint256 amount0, uint256 amount1, address indexed to)`
        /// Aerodrome: `Burn(address indexed sender, address indexed to, uint256 amount0, uint256 amount1)`
        ///
        /// topic0: keccak256("Burn(address,address,uint256,uint256)")
        ///         = 0x5d624aa9c148153ab3446c1b154f660ee7701e549fe9b62dab7171b1c80e6fa8
        ///
        /// Source: IPool.sol (aerodrome-finance/contracts), fetched 2026-04-24 via WebFetch.
        /// Verified: SIGNATURE_HASH cross-checked in tests.
        event Burn(
            address indexed sender,
            address indexed to,
            uint256 amount0,
            uint256 amount1
        );
    }
}

