// ---------------------------------------------------------------------------
// DecodeError — decoder-specific error type
// ---------------------------------------------------------------------------

/// Decoder-specific error returned when log data cannot be ABI-decoded.
#[derive(Debug, thiserror::Error)]
pub enum DecodeError {
    #[error("topic count mismatch: expected {expected}, got {actual}")]
    TopicMismatch { expected: usize, actual: usize },

    #[error("data length mismatch: expected {expected} bytes, got {actual}")]
    DataLength { expected: usize, actual: usize },

    #[error("ABI decode error: {0}")]
    AbiFailed(String),
}

impl From<DecodeError> for AdapterError {
    fn from(e: DecodeError) -> Self {
        AdapterError::DecodeError {
            context: "ethereum_decoder",
            reason: e.to_string(),
        }
    }
}

