// ---------------------------------------------------------------------------
// Log parsing helper
// ---------------------------------------------------------------------------

/// Parse a `RawLog` into the alloy `Log` structure needed by `SolEvent::decode_log`.
fn raw_log_to_alloy(log: &RawLog) -> Result<alloy::primitives::Log, DecodeError> {
    use alloy::primitives::{LogData, Bytes, B256};

    // Parse topics — each must be a 32-byte hex hash.
    let topics: Vec<B256> = log.topics.iter().enumerate().map(|(i, t)| {
        let stripped = t.strip_prefix("0x").unwrap_or(t);
        let bytes = hex::decode(stripped).map_err(|e| DecodeError::AbiFailed(
            format!("topic[{i}] hex decode: {e}")
        ))?;
        if bytes.len() != 32 {
            return Err(DecodeError::TopicMismatch { expected: 32, actual: bytes.len() });
        }
        let mut arr = [0u8; 32];
        arr.copy_from_slice(&bytes);
        Ok(B256::from(arr))
    }).collect::<Result<_, _>>()?;

    let log_data = LogData::new(topics, Bytes::from(log.data.clone()))
        .ok_or_else(|| DecodeError::AbiFailed("LogData::new failed".to_string()))?;

    Ok(alloy::primitives::Log {
        address: alloy::primitives::Address::ZERO, // not needed for event decode
        data: log_data,
    })
}

/// Check if the first topic of a `RawLog` matches the given event signature hash.
fn topic0_matches(log: &RawLog, expected: &alloy::primitives::FixedBytes<32>) -> bool {
    match log.topics.first() {
        Some(t) => {
            let stripped = t.strip_prefix("0x").unwrap_or(t);
            match hex::decode(stripped) {
                Ok(b) if b.len() == 32 => b.as_slice() == expected.as_slice(),
                _ => false,
            }
        }
        None => false,
    }
}

