/// Decode an ERC-20 Transfer log.
///
/// Returns `Ok(None)` on topic0 mismatch.
/// Returns `Ok(Some(DecodedTransfer))` on success.
/// Returns `Err` on malformed topics/data.
///
/// NOTE: This is the raw event value. Fee-on-transfer tokens may charge a fee
/// between the Transfer value and the amount received. Use balance-diff for
/// exact received amounts (future enhancement).
pub fn try_decode_transfer(log: &RawLog) -> Result<Option<DecodedTransfer>, AdapterError> {
    if !topic0_matches(log, &Transfer::SIGNATURE_HASH) {
        return Ok(None);
    }
    let alloy_log = raw_log_to_alloy(log)?;
    let decoded = Transfer::decode_log(&alloy_log)
        .map_err(|e| DecodeError::AbiFailed(e.to_string()))?;

    Ok(Some(DecodedTransfer {
        from: decoded.data.from,
        to: decoded.data.to,
        value: decoded.data.value,
        contract: log.address.clone(),
        block_number: log.block_number,
        tx_hash: log.tx_hash.clone(),
        log_index: log.log_index,
    }))
}

