/// Decode a Uniswap v3 Swap log.
///
/// Returns `Ok(None)` on topic0 mismatch.
///
/// Note: v3 Swap has a DIFFERENT topic0 than v2 Swap. Amounts are `int256` (signed).
/// Negative amount0 means token0 flowed out of the pool to the recipient.
pub fn try_decode_v3_swap(log: &RawLog) -> Result<Option<DecodedV3Swap>, AdapterError> {
    if !topic0_matches(log, &univ3::Swap::SIGNATURE_HASH) {
        return Ok(None);
    }
    let alloy_log = raw_log_to_alloy(log)?;
    let decoded = univ3::Swap::decode_log(&alloy_log)
        .map_err(|e| DecodeError::AbiFailed(e.to_string()))?;

    // int24 → i32: safe narrowing. int24 range is [-8388608, 8388607] which fits i32.
    let tick = decoded.data.tick.as_i32();

    // uint160 → U256: safe widening via ruint's From impl.
    let sqrt_price_x96 = U256::from(decoded.data.sqrtPriceX96);

    // uint128 → u128: same bit width, direct cast.
    let liquidity = decoded.data.liquidity;

    Ok(Some(DecodedV3Swap {
        sender: decoded.data.sender,
        recipient: decoded.data.recipient,
        amount0: decoded.data.amount0,
        amount1: decoded.data.amount1,
        sqrt_price_x96,
        liquidity,
        tick,
        pool: log.address.clone(),
        block_number: log.block_number,
        tx_hash: log.tx_hash.clone(),
    }))
}

