/// Decode a Uniswap V2 Factory `PairCreated` log.
///
/// Returns `Ok(None)` on topic0 mismatch (i.e. any log not from a UniV2 factory).
/// Returns `Ok(Some(DecodedV2PairCreated))` on success.
/// Returns `Err` on malformed topics/data.
///
/// # Address filtering
///
/// This function checks topic0 only. The caller must additionally verify that
/// `log.address` is a known UniV2 (or PancakeSwap V2 etc.) factory address.
/// The factory address set is per-chain (see `UNISWAP_V2_FACTORY_*` constants — Sprint 25).
///
/// # `pair_index` precision
///
/// The `unused` uint256 is the sequential pair count. It is narrowed to `u64`.
/// In practice, no factory will exceed `u64::MAX` pairs — the narrowing is safe.
pub fn try_decode_v2_pair_created(
    log: &RawLog,
) -> Result<Option<DecodedV2PairCreated>, AdapterError> {
    if !topic0_matches(log, &uniswap_v2_factory::PairCreated::SIGNATURE_HASH) {
        return Ok(None);
    }
    let alloy_log = raw_log_to_alloy(log)?;
    let decoded = uniswap_v2_factory::PairCreated::decode_log(&alloy_log)
        .map_err(|e| DecodeError::AbiFailed(e.to_string()))?;

    // uint256 pair index — safe narrowing to u64 (no factory reaches u64::MAX pairs).
    let pair_index = decoded.data.unused.saturating_to::<u64>();

    Ok(Some(DecodedV2PairCreated {
        token0: decoded.data.token0,
        token1: decoded.data.token1,
        pair: decoded.data.pair,
        pair_index,
        factory: log.address.clone(),
        block_number: log.block_number,
        tx_hash: log.tx_hash.clone(),
        log_index: log.log_index,
    }))
}

/// Decode a Uniswap V3 Factory `PoolCreated` log.
///
/// Returns `Ok(None)` on topic0 mismatch.
/// Returns `Ok(Some(DecodedV3PoolCreated))` on success.
/// Returns `Err` on malformed topics/data.
///
/// # Address filtering
///
/// This function checks topic0 only. The caller must additionally verify that
/// `log.address` is a known UniV3 factory address for the target chain
/// (see `UNISWAP_V3_FACTORY_*` constants — Sprint 25).
///
/// # `fee` precision
///
/// The `fee` field is `uint24` in the ABI. It is widened to `u32` for storage.
/// Maximum uint24 = 16_777_215 bips = 1677.7% — physically impossible fee tier.
/// In practice Uniswap V3 uses 100, 500, 3000, 10000 bip tiers.
///
/// # `tick_spacing` precision
///
/// The `tickSpacing` field is `int24` in the ABI. It is narrowed to `i32`.
/// int24 range fits i32 exactly.
pub fn try_decode_v3_pool_created(
    log: &RawLog,
) -> Result<Option<DecodedV3PoolCreated>, AdapterError> {
    if !topic0_matches(log, &uniswap_v3_factory::PoolCreated::SIGNATURE_HASH) {
        return Ok(None);
    }
    let alloy_log = raw_log_to_alloy(log)?;
    let decoded = uniswap_v3_factory::PoolCreated::decode_log(&alloy_log)
        .map_err(|e| DecodeError::AbiFailed(e.to_string()))?;

    // uint24 fee → u32: safe widening (uint24 max = 16_777_215 < u32::MAX).
    let fee = decoded.data.fee.to::<u32>();
    // int24 tickSpacing → i32: safe narrowing (int24 fits i32).
    let tick_spacing = decoded.data.tickSpacing.as_i32();

    Ok(Some(DecodedV3PoolCreated {
        token0: decoded.data.token0,
        token1: decoded.data.token1,
        fee,
        tick_spacing,
        pool: decoded.data.pool,
        factory: log.address.clone(),
        block_number: log.block_number,
        tx_hash: log.tx_hash.clone(),
        log_index: log.log_index,
    }))
}

// ---------------------------------------------------------------------------
// Factory event → common PoolEvent conversions
// ---------------------------------------------------------------------------

/// Convert a decoded UniV2 `PairCreated` event into a common `PoolEvent::Initialize`.
///
/// The `actor` address is the deployer (the `tx.from` of the factory call), which
/// must be supplied by the caller since it is not part of the factory log itself.
///
/// The `block_time` is the timestamp of the block in which the factory log appeared.
///
/// # Chain sensitivity
///
/// On BSC this factory event is emitted by PancakeSwap V2; the `DexKind` is set to
/// `PancakeSwapV2`. On all other chains it is `UniswapV2`.
///
/// # Returns
///
/// `Err(AdapterError)` if the alloy address → common address conversion fails
/// (malformed address in the decoded event — should not happen for well-formed logs
/// but propagated for safety).
pub fn pair_created_to_pool_event(
    decoded: &DecodedV2PairCreated,
    chain: mg_onchain_common::chain::Chain,
    actor: mg_onchain_common::chain::Address,
    block_time: chrono::DateTime<chrono::Utc>,
) -> Result<mg_onchain_common::event::PoolEvent, AdapterError> {
    use mg_onchain_common::chain::{Address, BlockRef, TxHash};
    use mg_onchain_common::event::{DexKind, PoolEvent, PoolEventKind};

    let token0_hex = format!("{}", decoded.token0);
    let token1_hex = format!("{}", decoded.token1);
    let pair_hex = format!("{}", decoded.pair);

    let token0 = Address::parse(chain, &token0_hex).map_err(|e| AdapterError::DecodeError {
        context: "pair_created_to_pool_event: token0",
        reason: e.to_string(),
    })?;
    let token1 = Address::parse(chain, &token1_hex).map_err(|e| AdapterError::DecodeError {
        context: "pair_created_to_pool_event: token1",
        reason: e.to_string(),
    })?;
    let pool = Address::parse(chain, &pair_hex).map_err(|e| AdapterError::DecodeError {
        context: "pair_created_to_pool_event: pair",
        reason: e.to_string(),
    })?;

    let tx_hash = TxHash::evm_from_hex(&decoded.tx_hash).map_err(|e| AdapterError::DecodeError {
        context: "pair_created_to_pool_event: tx_hash",
        reason: e.to_string(),
    })?;

    let dex = if chain == mg_onchain_common::chain::Chain::Bsc {
        DexKind::PancakeSwapV2
    } else {
        DexKind::UniswapV2
    };

    Ok(PoolEvent {
        chain,
        tx_hash,
        block: BlockRef::new(chain, decoded.block_number),
        block_time,
        pool,
        dex,
        kind: PoolEventKind::Initialize { token0, token1 },
        actor,
        log_index: decoded.log_index,
    })
}

/// Convert a decoded UniV3 `PoolCreated` event into a common `PoolEvent::Initialize`.
///
/// The `actor` and `block_time` semantics are identical to `pair_created_to_pool_event`.
///
/// On BSC, the event is assumed to be PancakeSwap V3 (which uses UniV3 factory ABI
/// for standard pools). On Base, it remains `UniswapV3` (Aerodrome uses its own
/// factory with different ABI — those events are decoded separately).
