    /// ABI-encode a 32-byte padded EVM address.
    fn encode_address_topic(addr: &str) -> String {
        // addresses in topics are 32 bytes, 0-padded on the left
        let stripped = addr.strip_prefix("0x").unwrap_or(addr);
        format!("0x{:0>64}", stripped)
    }

