    /// try_decode_aerodrome_mint: correct topic0 returns Some (happy path).
    #[test]
    fn aerodrome_mint_decode_happy_path() {
        // Aerodrome Mint topic0 == UniV2 Mint topic0.
        // Build a log with 2 topics (indexed sender) + 64-byte data (amount0, amount1).
        let topic0 = format!("0x{}", hex::encode(aerodrome::Mint::SIGNATURE_HASH.as_slice()));
        let sender_topic = "0x000000000000000000000000abcdabcdabcdabcdabcdabcdabcdabcdabcdabcd";
        // amount0 = 1e18, amount1 = 2e18 in 32-byte big-endian hex.
        let amount0 = "0000000000000000000000000000000000000000000000000de0b6b3a7640000";
        let amount1 = "0000000000000000000000000000000000000000000000001bc16d674ec80000";
        let data_hex = format!("{amount0}{amount1}");
        let data = hex::decode(&data_hex).unwrap();
        let log = RawLog {
            address: "0xaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa".into(),
            topics: vec![topic0, sender_topic.into()],
            data,
            block_number: 1_000_000,
            tx_hash: "0xbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb".into(),
            log_index: 0,
        };
        let result = try_decode_aerodrome_mint(&log)
            .expect("no decode error")
            .expect("must return Some on matching topic0");
        assert_eq!(result.pool, "0xaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa");
        assert_eq!(result.amount0, alloy::primitives::U256::from(1_000_000_000_000_000_000u128));
        assert_eq!(result.amount1, alloy::primitives::U256::from(2_000_000_000_000_000_000u128));
    }

