    /// Build a synthetic ERC-20 Transfer log (matches real ABI encoding).
    ///
    /// Transfer(from=0x1111...1, to=0x2222...2, value=100_000)
    ///
    /// Topics:
    ///   [0] topic0 (TRANSFER_TOPIC0)
    ///   [1] indexed from: 0x000...01111...1 (32 bytes, left-padded)
    ///   [2] indexed to:   0x000...02222...2
    /// Data:
    ///   value: 100_000 as uint256 (32 bytes, big-endian)
    fn make_transfer_log() -> RawLog {
        let topic0 = TRANSFER_TOPIC0.to_string();
        let from_topic = encode_address_topic("0x1111111111111111111111111111111111111111");
        let to_topic = encode_address_topic("0x2222222222222222222222222222222222222222");
        // value = 100_000 = 0x186A0; ABI uint256 big-endian: last 3 bytes at [29..31]
        let mut data = [0u8; 32];
        data[29] = 0x01;
        data[30] = 0x86;
        data[31] = 0xa0;
        RawLog {
            address: "0xdac17f958d2ee523a2206206994597c13d831ec7".to_string(), // USDT
            topics: vec![topic0, from_topic, to_topic],
            data: data.to_vec(),
            block_number: 21_000_000,
            tx_hash: "0xaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa".to_string(),
            log_index: 3,
        }
    }

    #[test]
    fn decode_transfer_happy_path() {
        let log = make_transfer_log();
        let decoded = try_decode_transfer(&log).unwrap().expect("should decode");
        assert_eq!(decoded.from, address!("0x1111111111111111111111111111111111111111"));
        assert_eq!(decoded.to, address!("0x2222222222222222222222222222222222222222"));
        assert_eq!(decoded.value, uint!(100_000_U256));
        assert_eq!(decoded.contract, "0xdac17f958d2ee523a2206206994597c13d831ec7");
        assert_eq!(decoded.block_number, 21_000_000);
        assert_eq!(decoded.log_index, 3);
    }

    #[test]
    fn decode_transfer_malformed_data_returns_err() {
        let mut log = make_transfer_log();
        log.data = vec![0xde, 0xad]; // too short for uint256
        let result = try_decode_transfer(&log);
        assert!(result.is_err(), "malformed data must return Err, not Ok(None)");
    }

