    // -----------------------------------------------------------------------
    // Happy-path tests — PancakeSwap V3 Swap
    // -----------------------------------------------------------------------

    /// Build a synthetic PancakeSwap V3 Swap log.
    ///
    /// Swap(sender=0x1111..., recipient=0x2222...,
    ///      amount0=-1000, amount1=2000, sqrtPriceX96=1, liquidity=5000,
    ///      tick=100, protocolFeesToken0=10, protocolFeesToken1=0)
    ///
    /// Indexed topics: topic0 = PANCAKE_V3_SWAP_TOPIC0, topic1 = sender, topic2 = recipient.
    /// Non-indexed data (ABI-encoded, 7 × 32 bytes = 224 bytes):
    ///   amount0    = -1000 (int256: two's complement → big-endian 32 bytes)
    ///   amount1    = 2000  (int256: positive → 32 bytes, 0-padded)
    ///   sqrtPrice  = 1     (uint160 → 32 bytes)
    ///   liquidity  = 5000  (uint128 → 32 bytes)
    ///   tick       = 100   (int24 → padded to 32 bytes, positive)
    ///   feeToken0  = 10    (uint128 → 32 bytes)
    ///   feeToken1  = 0     (uint128 → 32 bytes)
    fn make_pancake_v3_swap_log() -> RawLog {
        let sender_topic = encode_address_topic("0x1111111111111111111111111111111111111111");
        let recipient_topic = encode_address_topic("0x2222222222222222222222222222222222222222");

        let mut data = vec![0u8; 7 * 32];

        // amount0 = -1000 (int256 two's complement)
        // -1000 in 256-bit two's complement: 0xffff...fc18
        let neg_1000 = (-1000i64) as i128;
        let neg_bytes = neg_1000.to_be_bytes(); // 16 bytes
        // Fill first 16 bytes with 0xFF (sign extension for negative i256)
        for b in data[0..16].iter_mut() {
            *b = 0xFF;
        }
        // Last 16 bytes: i128 big-endian
        data[16..32].copy_from_slice(&neg_bytes);

        // amount1 = 2000 (int256, positive → 0-padded 32 bytes)
        data[32 + 30] = 0x07;
        data[32 + 31] = 0xD0; // 0x07D0 = 2000

        // sqrtPriceX96 = 1 (uint160 → last byte = 1)
        data[64 + 31] = 0x01;

        // liquidity = 5000 (uint128)
        data[96 + 30] = 0x13;
        data[96 + 31] = 0x88; // 0x1388 = 5000

        // tick = 100 (int24, stored as int256 in ABI → 0-padded, value 0x64)
        data[128 + 31] = 0x64; // 100

        // protocolFeesToken0 = 10 (uint128)
        data[160 + 31] = 0x0A;

        // protocolFeesToken1 = 0 (already zeroed)

        RawLog {
            address: "0xPancakeV3Pool00000000000000000000000000".to_string(),
            topics: vec![
                PANCAKE_V3_SWAP_TOPIC0.to_string(),
                sender_topic,
                recipient_topic,
            ],
            data,
            block_number: 38_000_000, // BSC block
            tx_hash: "0xdddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddd".to_string(),
            log_index: 5,
        }
    }

    #[test]
    fn decode_pancake_v3_swap_happy_path() {
        let log = make_pancake_v3_swap_log();
        let decoded = try_decode_pancake_v3_swap(&log).unwrap().expect("should decode");
        assert_eq!(decoded.sender, address!("0x1111111111111111111111111111111111111111"));
        assert_eq!(decoded.recipient, address!("0x2222222222222222222222222222222222222222"));
        // amount0 = -1000 (negative → token0 flows OUT of pool)
        assert!(decoded.amount0.is_negative(), "amount0 must be negative");
        // amount1 = 2000 (positive → token1 flows IN to pool)
        assert!(decoded.amount1.is_positive(), "amount1 must be positive");
        assert_eq!(decoded.liquidity, 5000u128);
        assert_eq!(decoded.tick, 100i32);
        assert_eq!(decoded.protocol_fee_token0, 10u128);
        assert_eq!(decoded.protocol_fee_token1, 0u128);
        assert_eq!(decoded.pool, "0xPancakeV3Pool00000000000000000000000000");
        assert_eq!(decoded.block_number, 38_000_000);
    }

    #[test]
    fn decode_pancake_v3_swap_malformed_data_returns_err() {
        let mut log = make_pancake_v3_swap_log();
        log.data = vec![0x00; 10]; // too short for 7 × 32-byte fields
        assert!(try_decode_pancake_v3_swap(&log).is_err());
    }

