    // -----------------------------------------------------------------------
    // UniV2 PairCreated: build a synthetic valid log and happy-path decode.
    //
    // PairCreated(token0=0x1111...1, token1=0x2222...2, pair=0x3333...3, unused=5)
    //
    // ABI encoding:
    //   topics[0] = topic0
    //   topics[1] = indexed token0 (32-byte padded)
    //   topics[2] = indexed token1 (32-byte padded)
    //   data = ABI-encoded (address pair, uint256 unused) = 2×32 bytes
    //     [0..32]  pair address (left-padded to 32 bytes)
    //     [32..64] unused = 5 (uint256, big-endian)
    // -----------------------------------------------------------------------

    fn make_pair_created_log() -> RawLog {
        let token0_topic = encode_address_topic("0x1111111111111111111111111111111111111111");
        let token1_topic = encode_address_topic("0x2222222222222222222222222222222222222222");

        // data: pair address (32 bytes, left-padded) + uint256 unused=5
        let mut data = vec![0u8; 64];
        // pair = 0x3333...3: ABI address encoding is 12 zero bytes + 20 address bytes
        let pair_bytes = hex::decode("3333333333333333333333333333333333333333").unwrap();
        data[12..32].copy_from_slice(&pair_bytes);
        // unused = 5: uint256 big-endian, 5 at the last byte
        data[63] = 5;

        RawLog {
            address: "0x5C69bEe701ef814a2B6a3EDD4B1652CB9cc5aA6f".to_string(), // UniV2 factory (Ethereum)
            topics: vec![
                UNISWAP_V2_PAIR_CREATED_TOPIC0.to_string(),
                token0_topic,
                token1_topic,
            ],
            data,
            block_number: 21_500_000,
            tx_hash: "0xbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb"
                .to_string(),
            log_index: 0,
        }
    }

