    // -----------------------------------------------------------------------
    // UniV3 PoolCreated: build a synthetic valid log and happy-path decode.
    //
    // PoolCreated(token0=0x1111...1, token1=0x2222...2, fee=3000, tickSpacing=60, pool=0x4444...4)
    //
    // ABI encoding:
    //   topics[0] = topic0
    //   topics[1] = indexed token0 (32-byte padded)
    //   topics[2] = indexed token1 (32-byte padded)
    //   topics[3] = indexed fee (uint24, 32-byte padded) = 3000 = 0x0BB8
    //   data = ABI-encoded (int24 tickSpacing, address pool) = 2×32 bytes
    //     [0..32]  tickSpacing = 60 (int24, sign-extended to 32 bytes, big-endian)
    //     [32..64] pool address (left-padded to 32 bytes)
    // -----------------------------------------------------------------------

    fn make_pool_created_log() -> RawLog {
        let token0_topic = encode_address_topic("0x1111111111111111111111111111111111111111");
        let token1_topic = encode_address_topic("0x2222222222222222222222222222222222222222");
        // fee = 3000 = 0x0BB8, uint24 padded to 32 bytes
        let mut fee_topic = vec![0u8; 32];
        fee_topic[30] = 0x0B;
        fee_topic[31] = 0xB8;
        let fee_topic_hex = format!("0x{}", hex::encode(&fee_topic));

        // data: int24 tickSpacing=60 + address pool
        let mut data = vec![0u8; 64];
        // tickSpacing = 60 = 0x3C, big-endian in 32 bytes (positive, no sign extension needed)
        data[31] = 0x3C;
        // pool = 0x4444...4: ABI address encoding (12 zero bytes + 20 address bytes)
        let pool_bytes = hex::decode("4444444444444444444444444444444444444444").unwrap();
        data[32 + 12..64].copy_from_slice(&pool_bytes);

        RawLog {
            address: "0x1F98431c8aD98523631AE4a59f267346ea31F984".to_string(), // UniV3 factory
            topics: vec![
                UNISWAP_V3_POOL_CREATED_TOPIC0.to_string(),
                token0_topic,
                token1_topic,
                fee_topic_hex,
            ],
            data,
            block_number: 21_600_000,
            tx_hash: "0xcccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccc"
                .to_string(),
            log_index: 1,
        }
    }

    #[test]
    fn decode_v3_pool_created_happy_path() {
        let log = make_pool_created_log();
        let decoded = try_decode_v3_pool_created(&log).unwrap().expect("should decode");
        assert_eq!(
            decoded.token0,
            address!("0x1111111111111111111111111111111111111111")
        );
        assert_eq!(
            decoded.token1,
            address!("0x2222222222222222222222222222222222222222")
        );
        assert_eq!(decoded.fee, 3000u32, "fee must be 3000 bips (0.3%)");
        assert_eq!(decoded.tick_spacing, 60i32, "tickSpacing must be 60");
        assert_eq!(
            decoded.pool,
            address!("0x4444444444444444444444444444444444444444")
        );
        assert_eq!(decoded.factory, "0x1F98431c8aD98523631AE4a59f267346ea31F984");
        assert_eq!(decoded.block_number, 21_600_000);
    }

