    #[test]
    fn factory_topic0_constants_are_66_chars() {
        for (name, topic) in [
            ("UNIV2_PAIR_CREATED", UNISWAP_V2_PAIR_CREATED_TOPIC0),
            ("UNIV3_POOL_CREATED", UNISWAP_V3_POOL_CREATED_TOPIC0),
            ("AERODROME_POOL_CREATED", AERODROME_POOL_CREATED_TOPIC0),
        ] {
            assert_eq!(topic.len(), 66, "{name} must be 66 chars (0x + 64 hex)");
            assert!(topic.starts_with("0x"), "{name} must start with 0x");
        }
    }

    #[test]
    fn factory_topic0_distinct_from_pool_events() {
        // PairCreated must not collide with any pool-level event topic0
        assert_ne!(UNISWAP_V2_PAIR_CREATED_TOPIC0, UNISWAP_V2_SWAP_TOPIC0);
        assert_ne!(UNISWAP_V2_PAIR_CREATED_TOPIC0, UNISWAP_V2_MINT_TOPIC0);
        assert_ne!(UNISWAP_V2_PAIR_CREATED_TOPIC0, UNISWAP_V2_BURN_TOPIC0);
        // PoolCreated must not collide with any pool-level event topic0
        assert_ne!(UNISWAP_V3_POOL_CREATED_TOPIC0, UNISWAP_V3_SWAP_TOPIC0);
        assert_ne!(UNISWAP_V3_POOL_CREATED_TOPIC0, UNISWAP_V3_MINT_TOPIC0);
        assert_ne!(UNISWAP_V3_POOL_CREATED_TOPIC0, UNISWAP_V3_BURN_TOPIC0);
        // Factory events must be distinct from each other
        assert_ne!(UNISWAP_V2_PAIR_CREATED_TOPIC0, UNISWAP_V3_POOL_CREATED_TOPIC0);
    }

