    #[test]
    fn univ2_pair_created_to_pool_event_initialize() {
        use chrono::Utc;
        use mg_onchain_common::chain::{Address, Chain};
        use mg_onchain_common::event::{DexKind, PoolEventKind};

        let log = make_pair_created_log();
        let decoded = try_decode_v2_pair_created(&log).unwrap().expect("should decode");

        // Construct a dummy actor (deployer wallet).
        let actor = Address::parse(Chain::Ethereum, "0xdeaddeaddeaddeaddeaddeaddeaddeaddeaddead")
            .unwrap();
        let block_time = Utc::now();

        let pool_event = pair_created_to_pool_event(
            &decoded,
            Chain::Ethereum,
            actor.clone(),
            block_time,
        )
        .expect("conversion must succeed");

        // PoolEventKind must be Initialize with the correct token pair.
        match pool_event.kind {
            PoolEventKind::Initialize { ref token0, ref token1 } => {
                assert_eq!(
                    token0.as_str(),
                    "0x1111111111111111111111111111111111111111",
                    "token0 must match PairCreated indexed arg"
                );
                assert_eq!(
                    token1.as_str(),
                    "0x2222222222222222222222222222222222222222",
                    "token1 must match PairCreated indexed arg"
                );
            }
            other => panic!("expected Initialize, got {other:?}"),
        }

        // Pool address = pair from PairCreated.
        assert_eq!(
            pool_event.pool.as_str(),
            "0x3333333333333333333333333333333333333333"
        );

        // Chain / dex / actor.
        assert_eq!(pool_event.chain, Chain::Ethereum);
        assert_eq!(pool_event.dex, DexKind::UniswapV2, "Ethereum → UniswapV2");
        assert_eq!(pool_event.actor.as_str(), actor.as_str());

        // Block height from the decoded log.
        assert_eq!(pool_event.block.height, 21_500_000);
    }

