    // -----------------------------------------------------------------------

    // -----------------------------------------------------------------------
    // Track B (Sprint 45): Aerodrome factory PoolCreated
    //
    // Aerodrome factory (Base chain): `0x420dd381b31aef6683db6b902084cb0ffece40da`
    // ABI source: IPoolFactory.sol (aerodrome-finance/contracts), fetched 2026-04-24.
    //
    // event PoolCreated(address indexed token0, address indexed token1,
    //                   bool indexed stable, address pool, uint256)
    //
    // topic0 ≠ UniV2 PairCreated ≠ UniV3 PoolCreated (different ABI = different keccak256).
    //
    // Build a synthetic log:
    //   PoolCreated(token0=0x5555...5, token1=0x6666...6, stable=false,
    //               pool=0x7777...7, pool_count=1)
    //
    //   topics[0] = AERODROME_POOL_CREATED_TOPIC0
    //   topics[1] = token0 (address, indexed)
    //   topics[2] = token1 (address, indexed)
    //   topics[3] = stable (bool, indexed — false = 32-byte zero)
    //   data      = ABI-encoded (address pool, uint256 pool_count)
    //             = 2 × 32 bytes
    //               [0..32]  pool address (left-padded)
    //               [32..64] pool_count = 1
    // -----------------------------------------------------------------------

    fn make_aerodrome_pool_created_log() -> RawLog {
        let token0_topic = encode_address_topic("0x5555555555555555555555555555555555555555");
        let token1_topic = encode_address_topic("0x6666666666666666666666666666666666666666");
        // stable = false → indexed bool = 32-byte zero
        let stable_topic_hex = format!("0x{}", hex::encode([0u8; 32]));

        // data: address pool (32 bytes left-padded) + uint256 pool_count=1
        let mut data = vec![0u8; 64];
        let pool_bytes = hex::decode("7777777777777777777777777777777777777777").unwrap();
        data[12..32].copy_from_slice(&pool_bytes);
        data[63] = 1; // pool_count = 1

        RawLog {
            address: "0x420dd381b31aef6683db6b902084cb0ffece40da".to_string(), // Aerodrome factory
            topics: vec![
                AERODROME_POOL_CREATED_TOPIC0.to_string(),
                token0_topic,
                token1_topic,
                stable_topic_hex,
            ],
            data,
            block_number: 13_000_000, // Base block
            tx_hash: "0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff"
                .to_string(),
            log_index: 3,
        }
    }

    /// topic0 cross-check: AERODROME_POOL_CREATED_TOPIC0 must match sol! SIGNATURE_HASH.
    ///
    /// This test derives the topic0 from the alloy sol! SIGNATURE_HASH at compile time
    /// and asserts it equals the hardcoded constant. Fails fast if the constant is wrong.
    #[test]
    fn aerodrome_pool_created_topic0_matches_sol() {
        let expected = format!(
            "0x{}",
            hex::encode(aerodrome_factory::PoolCreated::SIGNATURE_HASH.as_slice())
        );
        assert_eq!(
            expected, AERODROME_POOL_CREATED_TOPIC0,
            "Aerodrome PoolCreated SIGNATURE_HASH must match AERODROME_POOL_CREATED_TOPIC0 constant. \
             Actual sol! hash: {expected}"
        );
    }

