    /// Sprint 24 Track 2: compute Clanker TokenCreated topic0 via alloy keccak256.
    ///
    /// Event signature (from clanker-sdk v4 ABI, confirmed from Basescan contract source
    /// retrieved 2026-04-24): TokenCreated with 16 parameters.
    ///
    /// The canonical ABI-encoded signature used for topic0 computation includes
    /// all parameter types in canonical form, without parameter names or `indexed` markers.
    ///
    /// This test prints the computed topic0 so it can be verified against an actual
    /// Clanker deployment TX on Basescan. When the topic0 is confirmed against a live TX,
    /// update `CLANKER_TOKEN_DEPLOYED_TOPIC0_SPEC_NOTE` in launchpad_decoder.rs with the
    /// verified hex string.
    ///
    /// Source: clanker-sdk/src/abi/v4/Clanker.ts (confirmed from GitHub 2026-04-24).
    #[test]
    fn clanker_token_created_topic0_computation() {
        use alloy::primitives::keccak256;
        use alloy::primitives::hex;

        // Canonical ABI event signature — parameter names and `indexed` markers are
        // omitted (keccak256 is computed over the canonical form only).
        let sig = b"TokenCreated(address,address,address,string,string,string,string,string,int24,address,bytes32,address,address,address,uint256,address[])";
        let hash = keccak256(sig);
        let topic0_hex = format!("0x{}", hex::encode(hash));

        // Print for manual verification against Basescan TX.
        println!("Clanker TokenCreated topic0: {topic0_hex}");

        // Assert the format is correct: 0x + 64 lowercase hex chars.
        assert!(
            topic0_hex.starts_with("0x"),
            "topic0 must start with 0x"
        );
        assert_eq!(
            topic0_hex.len(),
            66, // 2 (0x) + 64 (hex chars)
            "topic0 must be exactly 66 chars (0x + 64 hex)"
        );

        // Record the computed value for REFERENCES.md / launchpad_decoder.rs update.
        // MANUAL VERIFICATION REQUIRED: confirm this matches topic0 of a live Clanker
        // deployment TX on Basescan (factory: 0xE85A59c628F7d27878ACeB4bf3b35733630083a9).
        // The ABI was read from clanker-sdk/src/abi/v4/Clanker.ts on 2026-04-24.
        // TODO(next-sprint): Decode a confirmed Basescan TX and compare topic0 bytes.
        // If the event emitted by the factory uses a different parameter order than
        // documented in the SDK ABI, the topic0 will differ.
        let _ = topic0_hex; // used via println! above
    }
